import os
from datetime import datetime, timedelta
import pickle
from flask import Flask, request, jsonify

app = Flask(__name__)
CACHE_DIR = 'cache'
if not os.path.exists(CACHE_DIR):
    os.makedirs(CACHE_DIR)

def get_cache_file_name(endpoint):
    return f"{CACHE_DIR}/{endpoint}.pickle"

def load_from_cache(endpoint):
    try:
        with open(get_cache_file_name(endpoint), 'rb') as file:
            data = pickle.load(file)
            if datetime.now() - data['timestamp'] > timedelta(seconds=300):
                return None
            else:
                return data['response']
    except FileNotFoundError:
        pass
    return None

def save_to_cache(endpoint, response, timestamp):
    with open(get_cache_file_name(endpoint), 'wb') as file:
        pickle.dump({'response': response, 'timestamp': timestamp}, file)

@app.route('/api/v1/<endpoint>')
def api(endpoint):
    cached_data = load_from_cache(endpoint)
    if cached_data:
        return jsonify(cached_data)

    # Expensive API call or computation
    response = {...}  # Replace this with your actual API response

    save_to_cache(endpoint, response, datetime.now())
    return jsonify(response)

if __name__ == "__main__":
    app.run(debug=True)